  INSERT INTO knowledge_sop_steps (sop_id, step_number, title, content, step_type, order_index)
  VALUES
    (v_sop_id, 1, 'Objetivo', 'Maximizar o retorno de cada evento do setor em que a TBO participa. A participação em eventos é um dos principais canais de posicionamento no mercado imobiliário de alto padrão. Sem processo, é gasto. Com processo, é investimento com ROI mensurável.', 'step', 0),
    (v_sop_id, 2, 'Escopo', E'**Quem executa:** Ruy (decisão + estratégia) + Equipe de Relacionamentos (operação) + Marco (quando palestrante ou representação institucional)\n**Quando se aplica:** Todo evento com participação formal da TBO como patrocinadora, expositora, palestrante ou convidada institucional\n**Limites:** Não cobre eventos internos da TBO. Capacitação da equipe segue SOP tbo-rh-009 (PDI).', 'step', 1),
    (v_sop_id, 3, 'RACI', E'| Atividade | Responsável | Aprovador | Consultado | Informado |\n|---|---|---|---|---|\n| Mapeamento anual | Ruy | Marco | — | Liderança |\n| Decisão de participação | Ruy | Marco | — | Liderança |\n| Aprovação de budget | Marco | — | Ruy | Financeiro |\n| Preparação de materiais | Marco (Dir. Criativo) | Ruy | BU envolvida | — |\n| Briefing de participação | Ruy | Marco | Participantes | — |\n| Follow-up pós-evento | Ruy + Participantes | Marco | — | — |\n| Registro de resultados | Ruy | Marco | — | Liderança |', 'step', 2),
    (v_sop_id, 4, 'Pré-requisitos', E'- Budget anual de relacionamentos aprovado por Marco\n- Calendário de eventos do setor mapeado (SECOVI, ABR, Real Estate Summit, etc.)\n- Deck institucional da TBO atualizado (versão evento)\n- Cards de apresentação digital com QR code\n- Critérios de avaliação de eventos definidos', 'step', 3),
    (v_sop_id, 5, 'Procedimento', E'**FASE 1: Mapeamento e Seleção (Jan)**\n1. Mapear eventos: imobiliário (SECOVI, ABR), design/arq (CasaCor, Brasil Arquitetura), negócios (LIDE, Endeavor), premiações (Prêmio Master, Trophy SECOVI)\n2. Critério de seleção (score 1-5): público-alvo, visibilidade, geração de negócio, posicionamento, custo-benefício\n   → Score mínimo para participar: 18/25\n3. Categorizar: Nível 1 (stand/palestra) | Nível 2 (presença representativa) | Nível 3 (observação)\n4. Aprovar calendário com Marco até 15 de Jan\n\n**FASE 2: Preparação (D-30)**\n1. Montar kit: materiais físicos (banner, flyers) + digitais (deck, QR codes) + identificação (crachás TBO)\n2. Definir equipe por nível de participação\n3. Briefing de participação (D-7): objetivo, personas-alvo, mensagem-chave, abordagem, meta de contatos\n4. Pesquisar participantes confirmados: mapear 5-10 contatos prioritários\n\n**FASE 3: Execução**\n1. Chegar 30 min antes (stand/palestra) ou 15 min (circulação)\n2. Capturar contatos via LinkedIn (não e-mail) + anotar contexto no momento\n3. Para contatos prioritários: propor próximo passo antes de encerrar a conversa\n4. Gerar conteúdo para redes: insights do evento com posicionamento TBO\n\n**FASE 4: Follow-up (D+2)**\n1. Cada participante envia lista consolidada com nome, empresa, temperatura (quente/morno/frio), próximo passo\n2. Ruy consolida no CRM TBO OS\n3. Follow-up personalizado via LinkedIn (referenciar conversa específica)\n4. Leads quentes: agendar call em até 5 dias úteis\n\n**FASE 5: Avaliação (D+7)**\n1. Relatório: contatos gerados, oportunidades criadas, alcance de conteúdo, custo/contato, ROI\n2. Decisão: participar novamente? com qual formato?\n3. Arquivar no TBO OS > Relacionamentos > Eventos', 'step', 4),
    (v_sop_id, 6, 'Checklist de Validação', E'- [ ] Critério de seleção aplicado antes de confirmar participação\n- [ ] Budget aprovado por Marco antes de qualquer compromisso\n- [ ] Briefing de participação realizado (D-7)\n- [ ] Contatos prioritários mapeados antes do evento\n- [ ] Todos contatos registrados no CRM em até 24h\n- [ ] Follow-up personalizado enviado em até 48h\n- [ ] Leads quentes com próximo passo em até 5 dias úteis\n- [ ] Relatório produzido em até 7 dias\n- [ ] Decisão de participação futura documentada', 'checkpoint', 5),
    (v_sop_id, 7, 'Ferramentas e Recursos', E'- **CRM**: TBO OS > Relacionamentos > Contatos de Eventos\n- **Calendário**: Google Calendar "TBO Eventos"\n- **Materiais**: Google Drive > Relacionamentos > Eventos > [Ano]\n- **LinkedIn**: Marco e Ruy como porta-vozes institucionais\n- **Captura**: LinkedIn QR Code + CRM mobile + app de notas', 'tip', 6),
    (v_sop_id, 8, 'SLAs e Métricas', E'- **Score mínimo para participar**: 18/25\n- **Follow-up**: 100% dos contatos em até 48h\n- **Leads quentes com próximo passo**: até 5 dias úteis\n- **Relatório de resultado**: até 7 dias após o evento\n- **Meta de contatos qualificados**: ≥ 10 por participante por dia\n- **Meta de oportunidades**: ≥ 2 por evento Nível 1\n- **Budget por evento**: máx. 15% do budget anual de relacionamentos', 'note', 7),
    (v_sop_id, 9, 'Troubleshooting', E'**Equipe vai ao evento mas não traz contatos**\n→ Briefing insuficiente ou abordagem errada — revisitar objetivo, personas e abertura de conversa\n→ Se recorrente: enviar somente liderança\n\n**Conteúdo gerado no evento não performa**\n→ 80% do conteúdo deve gerar valor para quem não foi ao evento (insights, não ego)\n→ Pautar posts com antecedência: o que comentar sobre os temas?\n\n**Follow-up ignorado pelos contatos**\n→ Verificar: há referência específica da conversa na mensagem?\n→ 2 tentativas sem resposta: classificar como frio, manter no radar passivo\n\n**Evento não gerou ROI esperado**\n→ Documentar e investigar: evento errado? equipe errada? objetivo errado?\n→ Não repetir por inércia — reavaliar a cada edição', 'warning', 8),
    (v_sop_id, 10, 'Template: Briefing e Relatório de Evento', E'**Template Briefing:**\n```\nBriefing — [EVENTO] — [DATA]\nEquipe: [Nomes] | Tipo: [Stand/Palestra/Circulação]\nObjetivo: [O que queremos alcançar em 1-2 frases]\n\nPersonas-alvo:\n| Persona | Empresas | Abordagem |\n|---------|----------|----------|\n\nContatos Prioritários:\n| Nome | Empresa | LinkedIn | Abordagem |\n|------|---------|----------|----------|\n\nMensagem-chave TBO: [adaptada ao público do evento]\nMeta: ___ contatos/pessoa/dia | ___ oportunidades | ___ posts\n```\n\n**Template Relatório:**\n```\nRelatório — [EVENTO] — [DATA]\n\nResumo: [3-4 linhas: valeu ou não? principais resultados]\n\n| Indicador | Meta | Realizado |\n|-----------|------|----------|\n| Contatos qualificados | ___ | ___ |\n| Oportunidades no CRM | ___ | ___ |\n| Custo total | R$___ | R$___ |\n| Custo/contato | R$___ | R$___ |\n\nDestaques:\n- Contato mais relevante:\n- Insight de mercado:\n\nDecisão: [ ] Participar novamente | [ ] Formato diferente | [ ] Não participar\n```', 'tip', 9)
  ON CONFLICT (sop_id, step_number) DO UPDATE SET
